    "id": 25,
    "slug": "automated-ct-scan-analysis-could-fast-track-clinical-assessments",
    "cat": "Biologia",
    "catCls": "biologia",
    "img": "https://www.nih.gov/sites/default/files/styles/max_650x650/public/2026-03/20260304-brain.jpg?itok=AnRFoToA",
    "inline_images": [],
    "video": null,
